import { Button } from "reactstrap";

import React, { useState } from "react";
import { useHistory } from "react-router-dom";
// ** Store
import { useSelector } from "react-redux";
import TruckListTable from "../common/TruckListTable";

const QCApprover = () => {
  const history = useHistory();
  const UserDetails = useSelector((state) => (state && state.auth ? state.auth.userData : {}));

  const [tableFilter] = useState({
    plantIds: UserDetails.plantids,
    vehicleStatus: "2,3,4,5,6",
  });
  const actionsCol = (row) => {
    switch (row.VECHICAL_STATUS) {
      case "3":
        return (
          <Button.Ripple color="primary" onClick={(e) => onUpdateStatus(row.PI_REFID)}>
            {"Approve"}
          </Button.Ripple>
        );
      case "4":
      case "5":
      case "6":
        return (
          <Button.Ripple
            color="primary"
            onClick={(e) => {
              history.push(`/QAView:${row.PI_REFID}/AP`);
            }}
          >
            {"View QC"}
          </Button.Ripple>
        );
      default:
        return "";
    }
  };
  const onUpdateStatus = (id) => {
    history.push(`/QA:${id}`);
  };

  return (
    <div>
      <TruckListTable postData={tableFilter} actionCell={actionsCol} title={"Quality Deduction"} />
    </div>
  );
};

export default QCApprover;
